        };

        Self.isAdBlockOff = function() {
            return ((defaults.platform == 'desktop' &&
                typeof page_params.holiday_promo_prem != 'undefined') ||
                defaults.platform != 'desktop');
        };

        Self.showPreroll = function(prerollObj) {
